using UnityEngine;

/// <summary>
/// Bloco empurrável/arrastável (P6 — fichas do GDD: "Pode empurrar blocos?"
/// graduado; + correcção "puxar"). O bloco fica travado em X até:
///
/// - EMPURRAR (toque): qualquer player cuja forma tenha PushStrength
///   suficiente (AnimalFormData.pushStrength; dentro de água usa o maior
///   entre pushStrength e pushStrengthInWater — ex: Polvo "médios só em
///   água") desloca o bloco só por lhe encostar (OnCollisionStay2D).
/// - PUXAR (NOVO): formas com 'canPull' (e força suficiente) podem, ao
///   segurar Interagir junto ao bloco e andar para trás, arrastá-lo —
///   ver <see cref="Pull"/>, chamado por PullAbility. Mais lento que andar
///   normalmente ("com dificuldade").
///
/// Inimigos com 'canBePushed'... não empurram blocos; para inimigos usa-se
/// física normal. Este componente é para o puzzle de empurrar/puxar do player.
/// </summary>
[RequireComponent(typeof(Rigidbody2D), typeof(Collider2D))]
public class PushableBlock : MonoBehaviour
{
    [Header("Peso do Bloco")]
    [Tooltip("Força mínima de empurrão/puxão (da forma do player) para mover este bloco: Leves/Médios/Pesados/Grandes.")]
    public PushStrength requiredStrength = PushStrength.Leves;

    [Tooltip("Tempo (segundos) que o bloco continua 'solto' depois do último contacto/puxão válido (evita trancar a meio do movimento).")]
    [Min(0.05f)] public float unlockGraceTime = 0.15f;

    [Header("Puxar (canPull)")]
    [Tooltip("Fracção da velocidade do player aplicada ao bloco quando é puxado (ex: 0.4 = bem mais lento/'com dificuldade').")]
    [Range(0.05f, 1f)] public float pullSlowFactor = 0.4f;

    private Rigidbody2D _rb;
    private float _unlockedUntil;

    private void Awake()
    {
        _rb = GetComponent<Rigidbody2D>();
        Lock();
    }

    private void FixedUpdate()
    {
        if (Time.time > _unlockedUntil && (_rb.constraints & RigidbodyConstraints2D.FreezePositionX) == 0)
            Lock();
    }

    private void OnCollisionStay2D(Collision2D collision)
    {
        if (!collision.collider.CompareTag("Player")) return;

        var form = GetCurrentForm(collision.collider);
        if (form == null) return;

        bool inWater = IsInWater(collision.collider);

        if (CanBeMoved(form, inWater))
            Unlock();
    }

    /// <summary>
    /// Devolve a PushStrength efectiva da forma (considera pushStrengthInWater
    /// se "inWater" e for maior — ex: Polvo "médios só em água").
    /// </summary>
    public static PushStrength GetEffectiveStrength(AnimalFormData form, bool inWater)
    {
        if (form == null) return PushStrength.Nao;

        PushStrength effective = form.pushStrength;
        if (inWater && form.pushStrengthInWater > effective)
            effective = form.pushStrengthInWater;

        return effective;
    }

    /// <summary>true se a força efectiva da forma chega para mover este bloco (empurrar ou puxar).</summary>
    public bool CanBeMoved(AnimalFormData form, bool inWater)
    {
        var effective = GetEffectiveStrength(form, inWater);
        return effective >= requiredStrength && effective != PushStrength.Nao;
    }

    /// <summary>
    /// Arrasta o bloco a "desiredVelocity" reduzida por 'pullSlowFactor'
    /// (chamado continuamente por PullAbility enquanto o player puxa).
    /// Mantém a velocidade vertical actual (não voa nem cai mais rápido).
    /// </summary>
    public void Pull(Vector2 desiredVelocity)
    {
        Unlock();
        _rb.linearVelocity = new Vector2(desiredVelocity.x * pullSlowFactor, _rb.linearVelocity.y);
    }

    private static bool IsInWater(Collider2D playerCollider)
    {
        var wd = playerCollider.GetComponent<WaterDetector>();
        return wd != null && wd.IsInWater;
    }

    private static AnimalFormData GetCurrentForm(Collider2D playerCollider)
    {
        var switcher = playerCollider.GetComponent<FormSwitcher>();
        return switcher != null ? switcher.CurrentForm : null;
    }

    private void Lock()
    {
        _rb.linearVelocity = new Vector2(0f, _rb.linearVelocity.y);
        _rb.constraints = RigidbodyConstraints2D.FreezePositionX | RigidbodyConstraints2D.FreezeRotation;
    }

    private void Unlock()
    {
        _unlockedUntil = Time.time + unlockGraceTime;
        _rb.constraints = RigidbodyConstraints2D.FreezeRotation;
    }
}
